{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { size: A4 landscape; margin: 10mm 12mm 8mm 12mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 8.5pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 100%; margin: 0; padding: 0; }

  .hotel-logo { max-height: 52px; max-width: 95px; }
  .logo-box { display: inline-block; width: 44px; height: 44px; background: #1a1a2e; color: #fff; font-size: 15pt; font-weight: 700; text-align: center; line-height: 44px; border-radius: 5px; }
  .hotel-name { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 12pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 12px 0 14px; }

  .pill { display: inline-block; padding: 2px 9px; border-radius: 10px; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; margin-right: 5px; border: 1px solid #d1d5db; background: #f9fafb; color: #374151; }
  .pills-row { margin-bottom: 12px; }

  .section-title { font-size: 7.5pt; font-weight: 700; color: #fff; text-transform: uppercase; letter-spacing: 0.6px; background: #1a1a2e; padding: 6px 9px; margin-top: 12px; margin-bottom: 8px; }

  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td { padding: 4px 8px; font-size: 8.5pt; border-bottom: 1px solid #f1f5f9; vertical-align: middle; white-space: nowrap; }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 14%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 19%; color: #1a1a2e; font-weight: 400; }

  .stats-table { width: 100%; border-collapse: collapse; margin-bottom: 12px; }
  .stats-table td { border: 1px solid #e5e7eb; padding: 5px 8px; text-align: center; }
  .s-label { font-size: 6.5pt; color: #9ca3af; display: block; text-transform: uppercase; letter-spacing: 0.4px; }
  .s-value { font-size: 11pt; font-weight: 700; color: #1a1a2e; display: block; margin-top: 2px; }
  .s-value.green { color: #15803d; }
  .s-value.blue { color: #1d4ed8; }
  .s-value.purple { color: #6d28d9; }

  .data-table { width: 100%; border-collapse: collapse; font-size: 7.5pt; margin-bottom: 4px; }
  .data-table thead tr { background: #1a1a2e; color: #fff; }
  .data-table thead th { padding: 5px 5px; text-align: left; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.3px; white-space: nowrap; }
  .data-table thead th.num { text-align: right; }
  .data-table thead th.ctr { text-align: center; }
  .data-table tbody tr:nth-child(even) { background: #f9fafb; }
  .data-table tbody td { padding: 5px 5px; border-bottom: 1px solid #f1f5f9; color: #374151; vertical-align: middle; }
  .data-table tbody td.num { text-align: right; font-variant-numeric: tabular-nums; }
  .data-table tbody td.ctr { text-align: center; }
  .data-table tfoot tr { border-top: 2px solid #1a1a2e; background: #1a1a2e; color: #fff; }
  .data-table tfoot td { padding: 6px 5px; font-weight: 700; color: #fff; font-size: 8pt; }
  .data-table tfoot td.num { text-align: right; }

  .badge { display: inline-block; padding: 1px 6px; border-radius: 8px; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; white-space: nowrap; }
  .type-new       { background: #f3f4f6; color: #4b5563; border: 1px solid #e5e7eb; }
  .type-repeat    { background: #dbeafe; color: #1d4ed8; border: 1px solid #bfdbfe; }
  .type-vip       { background: #fef3c7; color: #b45309; border: 1px solid #fde68a; }
  .type-corporate { background: #ede9fe; color: #6d28d9; border: 1px solid #ddd6fe; }
  .type-long-stay { background: #dcfce7; color: #166534; border: 1px solid #bbf7d0; }
  .status-settled          { background: #dcfce7; color: #166534; border: 1px solid #bbf7d0; }
  .status-part-paid        { background: #fef3c7; color: #b45309; border: 1px solid #fde68a; }
  .status-outstanding      { background: #fee2e2; color: #b91c1c; border: 1px solid #fecaca; }
  .status-corporate-credit { background: #dbeafe; color: #1d4ed8; border: 1px solid #bfdbfe; }

  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 14px 0 8px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 14px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Guest Stay History</div>
        <div class="doc-subtitle">Guest Stay Records &amp; Revenue</div>
        <div class="doc-ref">
          <strong>Period:</strong> {{ filters.date_from }} &ndash; {{ filters.date_to }}<br>
          <strong>Generated:</strong> {{ generated_at }}<br>
          <strong>Prepared By:</strong> {{ prepared_by }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- PILLS -->
  <div class="pills-row">
    <span class="pill">{{ filters.date_from }} &ndash; {{ filters.date_to }}</span>
    {% if applied_filters.guest_type %}<span class="pill">{{ applied_filters.guest_type }}</span>{% endif %}
    {% if applied_filters.room_type %}<span class="pill">{{ applied_filters.room_type }}</span>{% endif %}
    {% if applied_filters.source %}<span class="pill">{{ applied_filters.source }}</span>{% endif %}
    {% if applied_filters.payment %}<span class="pill">{{ applied_filters.payment }}</span>{% endif %}
  </div>

  <!-- FILTERS -->
  <div class="section-title">Report Filters</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:14%" /><col style="width:19%" />
      <col style="width:14%" /><col style="width:19%" />
      <col style="width:14%" /><col style="width:19%" />
    </colgroup>
    <tr>
      <td class="info-key">Date From</td><td class="info-val">{{ filters.date_from }}</td>
      <td class="info-key">Date To</td><td class="info-val">{{ filters.date_to }}</td>
      <td class="info-key">Guest Type</td><td class="info-val">{{ applied_filters.guest_type or 'All' }}</td>
    </tr>
    <tr>
      <td class="info-key">Room Type</td><td class="info-val">{{ applied_filters.room_type or 'All' }}</td>
      <td class="info-key">Payment</td><td class="info-val">{{ applied_filters.payment or 'All' }}</td>
      <td class="info-key">Source</td><td class="info-val">{{ applied_filters.source or 'All' }}</td>
    </tr>
  </table>

  <!-- SUMMARY -->
  <div class="section-title">Summary</div>
  <table class="stats-table" cellpadding="0" cellspacing="0">
    <tr>
      <td><span class="s-label">Total Stays</span><span class="s-value">{{ stats.totalStays or 0 }}</span></td>
      <td><span class="s-label">Unique Guests</span><span class="s-value blue">{{ stats.uniqueGuests or 0 }}</span></td>
      <td><span class="s-label">Repeat Guests</span><span class="s-value purple">{{ stats.repeatGuests or 0 }}</span></td>
      <td><span class="s-label">Repeat Ratio</span><span class="s-value purple">{{ stats.repeatRatio or '0%' }}</span></td>
      <td><span class="s-label">Room Nights</span><span class="s-value">{{ stats.roomNights or 0 }}</span></td>
      <td><span class="s-label">Avg Stay</span><span class="s-value">{{ stats.avgStay or 0 }} nights</span></td>
      <td><span class="s-label">Total Revenue</span><span class="s-value green" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(stats.totalRevenue | float) }}</span></td>
    </tr>
  </table>

  <!-- DATA TABLE -->
  <div class="section-title">Guest Stay Records &mdash; {{ rows | length }} record(s)</div>
  {% if rows %}
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th class="ctr">#</th>
        <th>Guest ID</th>
        <th>Guest Name</th>
        <th>Phone</th>
        <th>Room</th>
        <th>Check-In</th>
        <th>Check-Out</th>
        <th class="ctr">Nights</th>
        <th>Type</th>
        <th class="num">Total Spend</th>
        <th class="num">Balance</th>
        <th>Status</th>
        <th>Source</th>
        <th>Last Visit</th>
        <th>Notes</th>
      </tr>
    </thead>
    <tbody>
      {% for row in rows %}
      <tr>
        <td class="ctr" style="color:#9ca3af;">{{ loop.index }}</td>
        <td style="font-size:7pt;font-weight:700;color:#1d4ed8;">{{ row.guestId or '&mdash;' }}</td>
        <td style="font-weight:700;color:#1a1a2e;">{{ row.guestName or 'Unknown Guest' }}</td>
        <td style="color:#6b7280;">{{ row.phone or '&mdash;' }}</td>
        <td style="font-weight:700;color:#1a1a2e;">{{ row.room or '&mdash;' }}</td>
        <td style="color:#6b7280;white-space:nowrap;font-size:7pt;">{{ row.checkin or '&mdash;' }}</td>
        <td style="color:#6b7280;white-space:nowrap;font-size:7pt;">{{ row.checkout or '&mdash;' }}</td>
        <td class="ctr">{{ row.nights or 0 }}</td>
        <td>
          {% set t = row.type or 'New' %}
          {% if t == 'New' %}<span class="badge type-new">New</span>
          {% elif t == 'Repeat' %}<span class="badge type-repeat">Repeat</span>
          {% elif t == 'VIP' %}<span class="badge type-vip">VIP</span>
          {% elif t == 'Corporate' %}<span class="badge type-corporate">Corporate</span>
          {% elif t == 'Long Stay' %}<span class="badge type-long-stay">Long Stay</span>
          {% else %}<span class="badge type-new">{{ t }}</span>{% endif %}
        </td>
        <td class="num" style="font-weight:600;">&#x20a6;{{ "{:,.0f}".format(row.totalSpend | float) }}</td>
        <td class="num" style="{% if row.balance | float > 0 %}color:#dc2626;font-weight:700;{% else %}color:#15803d;{% endif %}">
          &#x20a6;{{ "{:,.0f}".format(row.balance | float) }}
        </td>
        <td>
          {% set s = row.status or 'Outstanding' %}
          {% if s == 'Settled' %}<span class="badge status-settled">Settled</span>
          {% elif s == 'Part Paid' %}<span class="badge status-part-paid">Part Paid</span>
          {% elif s == 'Outstanding' %}<span class="badge status-outstanding">Outstanding</span>
          {% elif s == 'Corporate Credit' %}<span class="badge status-corporate-credit">Corp Credit</span>
          {% else %}<span class="badge status-outstanding">{{ s }}</span>{% endif %}
        </td>
        <td style="color:#6b7280;">{{ row.source or 'Direct' }}</td>
        <td style="color:#6b7280;font-size:7pt;">{{ row.lastVisit or 'First Visit' }}</td>
        <td style="color:#6b7280;font-size:7pt;max-width:120px;">{{ row.notes or '&mdash;' }}</td>
      </tr>
      {% endfor %}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="10" style="text-align:right;text-transform:uppercase;letter-spacing:0.5px;">Grand Total</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(totals.spend | float) }}</td>
        <td class="num" style="color:#fca5a5;">&#x20a6;{{ "{:,.0f}".format(totals.balance | float) }}</td>
        <td colspan="4">{{ totals.needFollowup or 0 }} stay(s) need follow-up</td>
      </tr>
    </tfoot>
  </table>
  {% else %}
  <p style="padding:16px;text-align:center;color:#9ca3af;font-size:8.5pt;border:1px dashed #e5e7eb;">No guest stay history records found for this period.</p>
  {% endif %}

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This report is generated by the {{ company }} Property Management System.<br>
          Guest retention insight: repeat guests represent <strong style="color:#374151;">{{ stats.repeatRatio or '0%' }}</strong> of selected stay records.<br>
          <strong style="color:#374151;">Period: {{ filters.date_from }} to {{ filters.date_to }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
